/**
 * tables.c — PHY constants and subcarrier tables for lib80211.
 *
 * All data is static const — no runtime initialization needed.
 * Values extracted from py80211/gen_ofdm_frame.py.
 */

#include "lib80211/constants.h"
#include <stddef.h>

/* ========================================================================
 * Rate table (802.11a, Table 17-3)
 * ======================================================================== */

const lib80211_rate_info LIB80211_RATE_TABLE[8] = {
    /*  rate  bits  mod  cr_n cr_d n_cbps n_dbps bpsc */
    {  6, 0x0B, 1, 1, 2,  48,  24, 1 },
    {  9, 0x0F, 1, 3, 4,  48,  36, 1 },
    { 12, 0x0A, 2, 1, 2,  96,  48, 2 },
    { 18, 0x0E, 2, 3, 4,  96,  72, 2 },
    { 24, 0x09, 4, 1, 2, 192,  96, 4 },
    { 36, 0x0D, 4, 3, 4, 192, 144, 4 },
    { 48, 0x08, 6, 2, 3, 288, 192, 6 },
    { 54, 0x0C, 6, 3, 4, 288, 216, 6 },
};

const lib80211_rate_info *lib80211_rate_lookup(int rate_mbps) {
    for (int i = 0; i < 8; i++) {
        if (LIB80211_RATE_TABLE[i].rate_mbps == rate_mbps)
            return &LIB80211_RATE_TABLE[i];
    }
    return NULL;
}

